WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/24.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/24.0/apex.js")}

var objID = "{!ServiceContract.Id}";

var finishedLocation;

if (window.parent.location.href=="/ui/desktop/DesktopPage") { 
finishedLocation = '/{!ServiceContract.Id}&isdtp=mn'; 
} else { 
finishedLocation = '/' + objID; 
}; 

if (objID.length != 0) {

// Make a synchronous call to Apex Web service method
var result = sforce.apex.execute(
"ServiceContractButton", // Class
"cloneServiceContract", // method
{serviceContractId: objID});

// createAttempt() returns new Service Contract page
if (result != '') {
window.location.href = '/' + result;
}

} else if (objID.length == 0) {

alert("No Service Contract has been cloned.");
}
